class BootstrapEnhancedDropdowns{constructor(options={}){this.options={splitButtonSelector:".bs-dropdown-wrapper",caretSelector:".bs-dropdown-caret",submenuSelector:".bs-dropdown-submenu",fullToggleSelector:".dropdown-toggle",debug:false,...options};this.init()}init(){if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",(()=>this.setupDropdowns()))}else{this.setupDropdowns()}}setupDropdowns(){this.initSplitButtonDropdowns();this.initSubmenuDropdowns();this.initAutoColumns()}initSplitButtonDropdowns(){const splitButtons=document.querySelectorAll(this.options.splitButtonSelector);splitButtons.forEach((splitButton=>{const caretButton=splitButton.querySelector(this.options.caretSelector);const linkElement=splitButton.querySelector(".nav-link:not("+this.options.fullToggleSelector+")");if(!caretButton||!linkElement){return}let menuId=caretButton.getAttribute("data-bs-target")||caretButton.getAttribute("aria-controls");let menu;if(menuId){if(menuId.startsWith("#")){menuId=menuId.substring(1)}menu=document.getElementById(menuId)}if(!menu){menu=splitButton.nextElementSibling;if(menu&&!menu.classList.contains("dropdown-menu")){menu=null}}if(!menu){return}let dropdownInstance=new bootstrap.Dropdown(caretButton);dropdownInstance._menu=menu;caretButton.addEventListener("click",(event=>{event.stopPropagation();dropdownInstance.toggle()}));caretButton.addEventListener("keydown",(event=>{if(event.key==="Enter"||event.key===" "){event.preventDefault();event.stopPropagation();dropdownInstance.toggle()}}));caretButton.addEventListener("show.bs.dropdown",(()=>{caretButton.setAttribute("aria-expanded","true")}));caretButton.addEventListener("hide.bs.dropdown",(()=>{caretButton.setAttribute("aria-expanded","false")}));this.setupMenuKeyboardNavigation(menu,caretButton,true)}))}initSubmenuDropdowns(){const submenuDropdowns=document.querySelectorAll(this.options.submenuSelector);submenuDropdowns.forEach((submenu=>{const itemWrapper=submenu.querySelector(".bs-dropdown-item-wrapper");let toggleElement,linkElement,menu,isSplitButton=false;if(itemWrapper){linkElement=itemWrapper.querySelector(".dropdown-item:not("+this.options.fullToggleSelector+")");toggleElement=itemWrapper.querySelector(this.options.caretSelector);isSplitButton=true}else{toggleElement=submenu.querySelector(this.options.fullToggleSelector)}if(!toggleElement){return}menu=submenu.querySelector(".dropdown-menu");if(!menu){return}let labelledById="";if(isSplitButton&&linkElement){labelledById=linkElement.id||""}else if(toggleElement){labelledById=toggleElement.id||""}if(!menu.id&&labelledById){menu.id=labelledById+"-menu"}if(labelledById){menu.setAttribute("aria-labelledby",labelledById)}if(toggleElement){if(menu.id&&!toggleElement.hasAttribute("aria-controls")){toggleElement.setAttribute("aria-controls",menu.id)}}let bsDropdownInstance=new bootstrap.Dropdown(toggleElement);bsDropdownInstance._menu=menu;toggleElement.addEventListener("click",(event=>{event.stopPropagation();if(toggleElement.tagName==="A"&&(toggleElement.getAttribute("href")==="#"||toggleElement.getAttribute("href")==="")){event.preventDefault()}bsDropdownInstance.toggle()}));toggleElement.addEventListener("keydown",(event=>{if(event.key==="Enter"||event.key===" "){event.preventDefault();event.stopPropagation();bsDropdownInstance.toggle()}}));toggleElement.addEventListener("show.bs.dropdown",(()=>{toggleElement.setAttribute("aria-expanded","true");submenu.classList.add("show")}));toggleElement.addEventListener("shown.bs.dropdown",(()=>{const firstItem=menu.querySelector(".dropdown-item:not(.disabled)");if(firstItem){firstItem.focus()}}));toggleElement.addEventListener("hide.bs.dropdown",(()=>{toggleElement.setAttribute("aria-expanded","false");submenu.classList.remove("show")}));this.setupMenuKeyboardNavigation(menu,toggleElement,isSplitButton)}))}setupMenuKeyboardNavigation(menu,toggleElement,isSplitButton){menu.addEventListener("keydown",(event=>{const items=Array.from(menu.querySelectorAll(".dropdown-item:not(.disabled)"));if(items.length===0)return;const currentIndex=items.indexOf(document.activeElement);let handled=false;if(event.key==="ArrowDown"){const nextIndex=currentIndex>=0?(currentIndex+1)%items.length:0;items[nextIndex].focus();handled=true}else if(event.key==="ArrowUp"){const prevIndex=currentIndex>=0?(currentIndex-1+items.length)%items.length:items.length-1;items[prevIndex].focus();handled=true}else if(event.key==="Escape"||!isSplitButton&&event.key==="ArrowLeft"||isSplitButton&&event.key==="ArrowLeft"&&document.activeElement===items[0]){if(toggleElement&&"hide"in toggleElement){toggleElement.hide()}else if(toggleElement&&toggleElement._element){bootstrap.Dropdown.getInstance(toggleElement._element).hide()}else if(toggleElement){bootstrap.Dropdown.getInstance(toggleElement).hide()}toggleElement.focus();handled=true}else if(event.key==="Tab"){if(currentIndex===items.length-1&&!event.shiftKey||currentIndex===0&&event.shiftKey){setTimeout((()=>{if(toggleElement&&"hide"in toggleElement){toggleElement.hide()}else if(toggleElement&&toggleElement._element){bootstrap.Dropdown.getInstance(toggleElement._element).hide()}else if(toggleElement){bootstrap.Dropdown.getInstance(toggleElement).hide()}}),0)}}if(handled){event.preventDefault();event.stopPropagation()}}))}initAutoColumns(){const topLevelMenus=document.querySelectorAll(".navbar-nav > .nav-item.dropdown > .dropdown-menu");topLevelMenus.forEach((menu=>{if(menu.closest(".bs-dropdown-submenu")){return}const items=Array.from(menu.children).filter((child=>child.tagName==="LI"));const itemCount=items.length;let numColumns=1;if(itemCount>=28){numColumns=5}else if(itemCount>=21){numColumns=4}else if(itemCount>=15){numColumns=3}else if(itemCount>=8){numColumns=2}for(let i=1;i<=5;i++){menu.classList.remove(`dropdown-menu-columns-${i}`)}const parentLi=menu.closest(".nav-item.dropdown");if(parentLi){parentLi.classList.remove("dropdown-full-width")}if(itemCount>0){if(numColumns>1){menu.classList.add(`dropdown-menu-columns-${numColumns}`)}if(numColumns>=3&&parentLi){parentLi.classList.add("dropdown-full-width")}}}))}}if(typeof module!=="undefined"&&module.exports){module.exports=BootstrapEnhancedDropdowns}else if(typeof define==="function"&&define.amd){define([],(function(){return BootstrapEnhancedDropdowns}))}else{window.BootstrapEnhancedDropdowns=BootstrapEnhancedDropdowns}